export default "import React, { ReactNode, useState } from 'react';\r\nimport { QueryModule } from 'joymap';\r\n\r\nexport const digitalInputs = {\r\n  A: {\r\n    borderRadius: '30px',\r\n    top: '100px',\r\n    right: '45px',\r\n    width: '30px',\r\n    height: '30px',\r\n    transform: 'translate(-25px, 49px)',\r\n  },\r\n  B: {\r\n    borderRadius: '30px',\r\n    top: '100px',\r\n    right: '45px',\r\n    width: '30px',\r\n    height: '30px',\r\n    transform: 'translateY(25px)',\r\n  },\r\n  X: {\r\n    borderRadius: '30px',\r\n    top: '100px',\r\n    right: '45px',\r\n    width: '30px',\r\n    height: '30px',\r\n    transform: 'translate(-50px, 25px)',\r\n  },\r\n  Y: {\r\n    borderRadius: '30px',\r\n    top: '100px',\r\n    right: '45px',\r\n    width: '30px',\r\n    height: '30px',\r\n    transform: 'translateX(-25px)',\r\n  },\r\n  dpadLeft: {\r\n    borderRadius: '10px',\r\n    top: '100px',\r\n    left: '45px',\r\n    width: '40px',\r\n    height: '30px',\r\n    transform: 'translateY(30px)',\r\n  },\r\n  dpadRight: {\r\n    borderRadius: '10px',\r\n    top: '100px',\r\n    left: '45px',\r\n    width: '40px',\r\n    height: '30px',\r\n    transform: 'translate(55px, 30px)',\r\n  },\r\n  dpadDown: {\r\n    borderRadius: '10px',\r\n    top: '100px',\r\n    left: '45px',\r\n    width: '30px',\r\n    height: '40px',\r\n    transform: 'translate(32px, 50px)',\r\n  },\r\n  dpadUp: {\r\n    borderRadius: '10px',\r\n    top: '100px',\r\n    left: '45px',\r\n    width: '30px',\r\n    height: '40px',\r\n    transform: 'translateX(30px)',\r\n  },\r\n  start: {\r\n    borderRadius: '10px',\r\n    top: '106px',\r\n    right: '170px',\r\n    width: '30px',\r\n    height: '30px',\r\n  },\r\n  select: {\r\n    borderRadius: '10px',\r\n    top: '106px',\r\n    left: '170px',\r\n    width: '30px',\r\n    height: '30px',\r\n  },\r\n  home: {\r\n    borderRadius: '10px',\r\n    top: '144px',\r\n    left: '223px',\r\n    width: '40px',\r\n    height: '40px',\r\n  },\r\n} as const;\r\ntype DigitalNames = keyof typeof digitalInputs;\r\n\r\nconst analogInputs = {\r\n  L: { left: '150px' },\r\n  R: { right: '150px' },\r\n} as const;\r\ntype AnalogNames = keyof typeof analogInputs;\r\n\r\nconst shoulderInputs = {\r\n  L1: { backgroundImage: 'url(/assets/L1.png)' },\r\n  L2: { backgroundImage: 'url(/assets/L2.png)' },\r\n  R1: { transform: 'scaleX(-1)', backgroundImage: 'url(/assets/L1.png)' },\r\n  R2: { transform: 'scaleX(-1)', backgroundImage: 'url(/assets/L2.png)' },\r\n} as const;\r\ntype ShoulderNames = keyof typeof shoulderInputs;\r\n\r\ninterface GamepadProps {\r\n  backgroundColor: string;\r\n  pressedColor: string;\r\n  module: QueryModule;\r\n  name: string;\r\n  children: ReactNode;\r\n}\r\n\r\ninterface ButtonProps {\r\n  pressedColor: string;\r\n  module: QueryModule;\r\n  setWaitingFor: (value: string | null) => void;\r\n}\r\n\r\nfunction Stick({\r\n  inputName,\r\n  pressedColor,\r\n  module,\r\n  setWaitingFor,\r\n}: ButtonProps & { inputName: AnalogNames }) {\r\n  const [x, y] = module.getStick(inputName).value;\r\n  const { pressed } = module.getButton(`${inputName}3`);\r\n  const inputStyle = analogInputs[inputName];\r\n\r\n  return (\r\n    <div\r\n      className=\"absolute bottom-13.25 z-15 h-12.5 w-12.5 cursor-pointer rounded-[40px] border-[3px] border-black bg-gray-500\"\r\n      style={{\r\n        ...inputStyle,\r\n        transform: `translate(${x * 15}px, ${y * 15}px)`,\r\n        backgroundColor: pressed ? pressedColor : 'gray',\r\n      }}\r\n      onClick={() => {\r\n        if (module.isConnected()) {\r\n          module.stickBindOnPress(inputName, () => setWaitingFor(null));\r\n          setWaitingFor(inputName);\r\n        }\r\n      }}\r\n    />\r\n  );\r\n}\r\n\r\nfunction Digital({\r\n  inputName,\r\n  pressedColor,\r\n  module,\r\n  setWaitingFor,\r\n}: ButtonProps & { inputName: DigitalNames }) {\r\n  const { pressed } = module.getButton(inputName);\r\n  const inputStyle = digitalInputs[inputName];\r\n\r\n  return (\r\n    <div\r\n      className=\"absolute cursor-pointer\"\r\n      style={{\r\n        backgroundColor: pressed ? pressedColor : 'gray',\r\n        ...inputStyle,\r\n      }}\r\n      onClick={() => {\r\n        if (module.isConnected()) {\r\n          module.buttonBindOnPress(inputName, () => setWaitingFor(null));\r\n          setWaitingFor(inputName);\r\n        }\r\n      }}\r\n    />\r\n  );\r\n}\r\n\r\nfunction Shoulder({ inputName, module }: { inputName: ShoulderNames; module: QueryModule }) {\r\n  const { value } = module.getButton(inputName);\r\n  const inputStyle = shoulderInputs[inputName];\r\n\r\n  return (\r\n    <div className=\"absolute h-full w-full\" style={{ transform: `translateY(${value * 10}px)` }}>\r\n      <div className=\"-mt-2.5 h-full w-full\" style={inputStyle} />\r\n    </div>\r\n  );\r\n}\r\n\r\nexport default function Gamepad({\r\n  backgroundColor,\r\n  pressedColor,\r\n  module,\r\n  name,\r\n  children,\r\n}: GamepadProps) {\r\n  const [waitingFor, setWaitingFor] = useState<string | null>(null);\r\n  const isDisconnected = !module.isConnected();\r\n  const filter = isDisconnected ? 'brightness(40%)' : 'none';\r\n\r\n  return (\r\n    <div\r\n      style={{\r\n        position: 'relative',\r\n        flex: 1,\r\n        display: 'flex',\r\n        justifyContent: 'center',\r\n        alignItems: 'center',\r\n        flexDirection: 'column',\r\n        padding: '1.5rem',\r\n        maxWidth: '50%',\r\n        border: '4px dashed rgba(0, 0, 0, 0.5)',\r\n        minWidth: '500px',\r\n        backgroundColor: waitingFor ? 'red' : backgroundColor,\r\n        filter,\r\n      }}\r\n    >\r\n      <div style={{ position: 'relative', width: '484px', height: '300px', overflow: 'hidden' }}>\r\n        <span\r\n          style={{\r\n            position: 'absolute',\r\n            top: '60px',\r\n            width: '100%',\r\n            textAlign: 'center',\r\n            zIndex: 15,\r\n            fontSize: '2rem',\r\n            color: pressedColor,\r\n          }}\r\n        >\r\n          {name}\r\n        </span>\r\n        <img\r\n          style={{\r\n            position: 'absolute',\r\n            width: '100%',\r\n            height: '100%',\r\n            zIndex: 10,\r\n            pointerEvents: 'none',\r\n          }}\r\n          src=\"/assets/gamepad.png\"\r\n        />\r\n        {Object.keys(shoulderInputs).map((inputName) => (\r\n          <Shoulder key={inputName} inputName={inputName as ShoulderNames} module={module} />\r\n        ))}\r\n        {Object.keys(analogInputs).map((inputName) => (\r\n          <Stick\r\n            key={inputName}\r\n            inputName={inputName as AnalogNames}\r\n            pressedColor={pressedColor}\r\n            module={module}\r\n            setWaitingFor={setWaitingFor}\r\n          />\r\n        ))}\r\n        {Object.keys(digitalInputs).map((inputName) => (\r\n          <Digital\r\n            key={inputName}\r\n            inputName={inputName as DigitalNames}\r\n            pressedColor={pressedColor}\r\n            module={module}\r\n            setWaitingFor={setWaitingFor}\r\n          />\r\n        ))}\r\n      </div>\r\n      {!!waitingFor && (\r\n        <div\r\n          style={{\r\n            position: 'absolute',\r\n            display: 'flex',\r\n            justifyContent: 'center',\r\n            alignItems: 'center',\r\n            width: '100%',\r\n            height: '100%',\r\n            zIndex: 30,\r\n            color: 'white',\r\n            fontSize: '3rem',\r\n            background: 'rgba(0, 0, 0, 0.5)',\r\n          }}\r\n          onClick={() => {\r\n            module.cancelListen();\r\n            setWaitingFor(null);\r\n          }}\r\n        >\r\n          Rebinding {waitingFor}\r\n        </div>\r\n      )}\r\n      {children}\r\n    </div>\r\n  );\r\n}\r\n"