export default "import { LoremIpsum } from 'lorem-ipsum';\r\n\r\nconst lorem = new LoremIpsum({\r\n  sentencesPerParagraph: {\r\n    max: 8,\r\n    min: 4,\r\n  },\r\n  wordsPerSentence: {\r\n    max: 16,\r\n    min: 4,\r\n  },\r\n});\r\n\r\ntype CommandName =\r\n  | 'move'\r\n  | 'select'\r\n  | 'input'\r\n  | 'delete'\r\n  | 'forwardDelete'\r\n  | 'numberedList'\r\n  | 'bulletedList'\r\n  | 'enter'\r\n  | 'bold'\r\n  | 'italic'\r\n  | 'blockQuote'\r\n  | 'undo'\r\n  | 'redo';\r\n\r\nexport type CommandPrimitive = string | { text: string };\r\nexport type CommandValue = CommandPrimitive | (() => CommandPrimitive);\r\nexport type Command = [CommandName] | [CommandName, CommandValue];\r\n\r\nexport const commands: Record<string, [Command, Command, Command, Command]> = {\r\n  dpadUp: [\r\n    ['move', 'upward'],\r\n    ['select', 'upward'],\r\n    ['input', { text: '👆' }],\r\n    ['input', { text: '👍' }],\r\n  ],\r\n  dpadDown: [\r\n    ['move', 'downward'],\r\n    ['select', 'downward'],\r\n    ['input', { text: '👇' }],\r\n    ['input', { text: '👎' }],\r\n  ],\r\n  dpadLeft: [\r\n    ['move', 'backward'],\r\n    ['select', 'backward'],\r\n    ['input', { text: '👈' }],\r\n    ['input', { text: '🤛' }],\r\n  ],\r\n  dpadRight: [\r\n    ['move', 'forward'],\r\n    ['select', 'forward'],\r\n    ['input', { text: '👉' }],\r\n    ['input', { text: '🤜' }],\r\n  ],\r\n  A: [\r\n    ['input', { text: '😂' }],\r\n    ['input', { text: '🤣' }],\r\n    ['input', { text: '❤️' }],\r\n    ['input', { text: '😍' }],\r\n  ],\r\n  B: [\r\n    ['input', { text: '😊' }],\r\n    ['input', { text: '🤪' }],\r\n    ['input', { text: '😭' }],\r\n    ['input', { text: '🙏' }],\r\n  ],\r\n  X: [['delete'], ['forwardDelete'], ['numberedList'], ['bulletedList']],\r\n  Y: [['enter'], ['bold'], ['italic'], ['blockQuote']],\r\n  start: [\r\n    ['input', { text: '💩' }],\r\n    ['input', { text: '🔥' }],\r\n    ['input', { text: '🤔' }],\r\n    ['input', { text: '✔' }],\r\n  ],\r\n  select: [\r\n    ['undo'],\r\n    ['redo'],\r\n    ['input', () => ({ text: ` ${lorem.generateWords(1)}` })],\r\n    ['input', () => ({ text: ` ${lorem.generateSentences(1)}` })],\r\n  ],\r\n  home: [\r\n    ['input', { text: '🍑' }],\r\n    ['input', { text: '🍆' }],\r\n    ['input', { text: '🍌' }],\r\n    ['input', { text: '🦠' }],\r\n  ],\r\n};\r\n"